double ternarySearch(double lo, double hi) {
  while (hi - lo > 1e-9) {
    double m1 = lo + (hi-lo)/3;
    double m2 = hi - (hi-lo)/3;
    if (f(m1) < f(m2)) hi = m2;
    else               lo = m1;
  }
  return (lo+hi)/2;
}

struct TrieNode {
  TrieNode* children[26] = {};
  bool isEnd = false;
};
void insert(TrieNode* root, string word) {
  for (char c : word) {
    int i = c - 'a';
    if (!root->children[i])
      root->children[i] = new TrieNode();
    root = root->children[i];
  }
  root->isEnd = true;
}

struct TrieNode {
  TrieNode* ch[26] = {};
  int prefixCount = 0;
  bool isEnd = false;
};
int countPrefix(TrieNode* root, string prefix) {
  for (char c : prefix) {
    int i = c-'a';
    if (!root->ch[i]) return 0;
    root = root->ch[i];
  }
  return root->prefixCount;
}

