struct Point { double x, y; };

double cross(Point O, Point A, Point B) {
  return (A.x-O.x)*(B.y-O.y)
        -(A.y-O.y)*(B.x-O.x);
}
// cross > 0: counter-clockwise
// cross < 0: clockwise
// cross = 0: collinear

double lineIntersect(double a1,double b1,double c1,
                     double a2,double b2,double c2,
                     double& x, double& y) {
  double det = a1*b2-a2*b1;
  if(fabs(det)<1e-9) return false; // parallel
  x=(c1*b2-c2*b1)/det;
  y=(a1*c2-a2*c1)/det;
  return true;
}

