bool pointInPolygon(vector<Point>& poly, Point p) {
  int n=poly.size(), cnt=0;
  for(int i=0,j=n-1;i<n;j=i++) {
    if((poly[i].y>p.y)!=(poly[j].y>p.y) &&
       p.x < (poly[j].x-poly[i].x)*
             (p.y-poly[i].y)/
             (poly[j].y-poly[i].y)+poly[i].x)
      cnt++;
  }
  return cnt%2==1;
}

