// Recursive approach:
void gen(int idx, vector<int>& cur) {
  if(idx==n) { process(cur); return; }
  gen(idx+1, cur);             // exclude
  cur.push_back(arr[idx]);
  gen(idx+1, cur);             // include
  cur.pop_back();
}

void permute(vector<int>& arr, int l, int r) {
  if(l==r) { process(arr); return; }
  for(int i=l;i<=r;i++) {
    swap(arr[l], arr[i]);
    permute(arr, l+1, r);
    swap(arr[l], arr[i]); // backtrack
  }
}
